class OfflineDataManager {
  final List<OfflineDataEntry> _entries = [];
  
  String createEntry(String data) {
    final entry = OfflineDataEntry(data: data);
    _entries.add(entry);
    return entry.id;
  }
  
  List<OfflineDataEntry> getUnsyncedEntries() {
    return _entries.where((entry) => !entry.synced).toList();
  }
  
  void markAsSynced(String id) {
    final index = _entries.indexWhere((entry) => entry.id == id);
    if (index != -1) {
      _entries[index] = _entries[index].copyWith(synced: true);
    }
  }
  
  List<OfflineDataEntry> getAllEntries() {
    return List.unmodifiable(_entries);
  }
  
  void clearSyncedEntries() {
    _entries.removeWhere((entry) => entry.synced);
  }
}

